func (tr *transactionalReloader) reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
	status := api_v1.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339), AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
	defer func() {
		status.LastReloadSuccessful = err == nil
		if err == nil {
			status.ErrorCategory = "none"
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
		} else {
			configSuccess.Set(0)
			callback(false)
		}
		tr.status.record(status)
	}()

	conf, err := loadConfig(filename, enableExemplarStorage, logger)
	if err != nil {
		status.ErrorCategory = "load_error"
		status.ErrorMessage = err.Error()
		return err
	}

	for i, rl := range rls {
		started := time.Now()
		err := rl.reloader(conf)
		status.ReloaderTimingsMS[rl.name] = durationToInt64Millis(time.Since(started))
		if err == nil {
			status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
			continue
		}

		status.ErrorCategory = "apply_error"
		status.ErrorMessage = err.Error()
		status.FailedReloader = rl.name
		if i > 0 && tr.lastKnownGood != nil {
			status.RollbackAttempted = true
			status.RollbackSuccessful = true
			for _, rollback := range rls {
				if rollbackErr := rollback.reloader(tr.lastKnownGood); rollbackErr != nil {
					status.RollbackSuccessful = false
					status.ErrorCategory = "rollback_error"
					status.ErrorMessage = rollbackErr.Error()
					status.FailedReloader = rollback.name
					break
				}
			}
		}
		return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, err)
	}

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	tr.lastKnownGood = conf
	return nil
}

